import { createClient } from '@supabase/supabase-js'
import { NextResponse } from 'next/server'
export const dynamic = 'force-dynamic'
const COVER_B64 = ``
const CONTENT = `
<p>O Dia dos Namorados é uma das datas que mais movimentam pedidos de comida no Brasil. Casais querem comemorar, pedir algo especial e, muitas vezes, decidem na hora onde vão comprar. Nesse momento, um cupom de desconto bem pensado pode ser o empurrãozinho que faz o cliente escolher o seu cardápio e fechar o pedido.</p>
<p>A boa notícia é que criar cupons no seu cardápio digital leva poucos minutos. Veja o passo a passo completo para montar suas promoções e aproveitar a data para vender mais.</p>

<h2>Por que usar cupons no Dia dos Namorados</h2>
<p>O cupom faz três coisas ao mesmo tempo: atrai a atenção, cria senso de oportunidade e incentiva o cliente a gastar um pouco mais para aproveitar a vantagem. Em uma data emocional como o Dia dos Namorados, isso pesa ainda mais na decisão de compra. Alguns benefícios diretos:</p>
<ul>
<li><strong>Aumenta a conversão:</strong> quem estava em dúvida fecha o pedido por causa do desconto.</li>
<li><strong>Eleva o ticket médio:</strong> com um cupom de pedido mínimo, o cliente adiciona mais itens para atingir o valor.</li>
<li><strong>Cria recorrência:</strong> um cupom para a próxima compra traz o cliente de volta depois da data.</li>
<li><strong>Dá um motivo para divulgar:</strong> cupom é conteúdo que gera engajamento nas redes.</li>
</ul>

<h2>Passo a passo: como criar cupons no Cardápio Turbo</h2>

<h3>1. Acesse a área de Promoções</h3>
<p>No painel do <strong>Cardápio Turbo</strong>, entre na aba <strong>Promoções</strong>. É ali que você cria e gerencia todos os seus cupons.</p>

<h3>2. Crie o cupom e escolha o código</h3>
<p>Clique em criar novo cupom e defina um código fácil de lembrar e com a cara da data. Sugestões que funcionam bem no Dia dos Namorados:</p>
<ul>
<li><strong>AMOR10</strong> para 10 por cento de desconto</li>
<li><strong>CASAL15</strong> para pedidos a dois</li>
<li><strong>NAMORADOS</strong> para uma oferta especial do dia</li>
</ul>

<h3>3. Defina o tipo de desconto</h3>
<p>Escolha entre <strong>percentual</strong> (ex.: 10 por cento off) ou <strong>valor fixo</strong> (ex.: 10 reais de desconto). O percentual funciona bem para pedidos maiores, e o valor fixo passa uma sensação clara de economia em pedidos menores.</p>

<h3>4. Configure o pedido mínimo</h3>
<p>Defina um valor mínimo para o cupom valer, por exemplo a partir de 40 reais. Isso protege a sua margem e ainda incentiva o cliente a montar um pedido maior, perfeito para um jantar a dois.</p>

<h3>5. Ative o cupom e copie o link</h3>
<p>Ative o cupom e ele já passa a valer no seu cardápio. O cliente aplica o código na hora de fechar o pedido e o desconto entra automaticamente no total.</p>

<h2>Ideias de cupons que vendem no Dia dos Namorados</h2>
<ul>
<li><strong>Combo do casal:</strong> crie um combo romântico e ofereça um cupom exclusivo para ele.</li>
<li><strong>Frete grátis acima de um valor:</strong> use um cupom de valor fixo que cobre o frete em pedidos maiores.</li>
<li><strong>Sobremesa em dobro:</strong> divulgue um cupom que dá vantagem na sobremesa, item clássico da data.</li>
<li><strong>Cupom de retorno:</strong> entregue um código para a próxima compra junto com o pedido, transformando o cliente da data em cliente fiel.</li>
</ul>

<h2>Dicas para divulgar seus cupons</h2>
<p>Criar o cupom é só metade do trabalho. Para ele funcionar, as pessoas precisam saber que ele existe. Coloque o código na bio do Instagram, no status do WhatsApp e nos stories. Faça um post mostrando o desconto e o prazo. E aproveite para reforçar o clima da data com fotos caprichadas dos seus produtos.</p>
<p>Lembre de definir uma data limite para o cupom. A sensação de urgência ajuda o cliente a decidir mais rápido, o que é importante em uma data com pico de pedidos.</p>

<h2>Comece agora e aproveite a data</h2>
<p>Faltando poucos dias para o Dia dos Namorados, cada hora conta. Monte seus cupons, crie um combo romântico e divulgue nas redes. Em poucos minutos o seu cardápio estará pronto para receber os pedidos da data mais apaixonada do ano.</p>
<p><a href="https://cardapioturbo.com.br/register"><strong>Crie seu cardápio digital grátis no Cardápio Turbo</strong></a> e teste por 7 dias, sem cartão de crédito. Configure seus cupons, divulgue e veja os pedidos chegarem direto no seu WhatsApp.</p>
`
export async function GET(req: Request) {
  const url = new URL(req.url)
  if (url.searchParams.get('secret') !== 'turbo-seed-2026') return NextResponse.json({ error: 'unauthorized' }, { status: 401 })
  const supabase = createClient(process.env.NEXT_PUBLIC_SUPABASE_URL!, process.env.SUPABASE_SERVICE_ROLE_KEY!)
  const slug = 'como-montar-cupons-cardapio-digital-dia-dos-namorados'
  const buffer = Buffer.from(COVER_B64, 'base64')
  const path = `${slug}.png`
  await supabase.storage.from('blog').upload(path, buffer, { contentType: 'image/png', upsert: true })
  const coverUrl = supabase.storage.from('blog').getPublicUrl(path).data.publicUrl
  await supabase.from('blog_posts').delete().eq('slug', slug)
  const { data, error } = await supabase.from('blog_posts').insert({
    title: 'Como montar cupons no seu cardápio digital para o Dia dos Namorados',
    slug,
    excerpt: 'Cupons de desconto bem pensados fazem o casal escolher o seu cardápio. Veja o passo a passo para criar cupons no Dia dos Namorados e vender mais.',
    content: CONTENT,
    category: 'Marketing',
    author: 'Equipe Cardápio Turbo',
    cover_emoji: '🎟️',
    cover_image: coverUrl,
    read_minutes: 6,
    seo_title: 'Como montar cupons para o Dia dos Namorados no cardápio digital',
    seo_description: 'Aprenda a criar cupons de desconto no seu cardápio digital para o Dia dos Namorados, com passo a passo, ideias de codigos e dicas de divulgacao.',
    keywords: 'dia dos namorados, cupom de desconto, cardapio digital, promocao dia dos namorados, vender mais, cupom restaurante',
    published: true,
    published_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
  }).select('slug').single()
  if (error) return NextResponse.json({ error: error.message }, { status: 500 })
  return NextResponse.json({ ok: true, slug: data.slug, coverUrl })
}
